import axios from "axios";

/* =====================================================
   BASE CONFIGURATION
===================================================== */

const BASE_URL = "http://localhost:5000/api";

const api = axios.create({
  baseURL: BASE_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

/* =====================================================
   REQUEST INTERCEPTOR
   → Automatically attach JWT token
===================================================== */

api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  },
  (error) => Promise.reject(error)
);

/* =====================================================
   RESPONSE INTERCEPTOR
   → Global error handling
===================================================== */

api.interceptors.response.use(
  (response) => response,
  (error) => {
    console.error(
      "API ERROR:",
      error.response?.data?.message || error.message
    );

    return Promise.reject(
      error.response?.data || { message: "Server Error" }
    );
  }
);

/* =====================================================
   AUTH SERVICES
===================================================== */

// LOGIN
export const loginUser = async (email, password) => {
  try {
    const response = await api.post("/auth/login", {
      email,
      password,
    
    });

    // Save token if backend sends it
    if (response.data.token) {
      localStorage.setItem("token", response.data.token);
    }

    return response.data;
  } catch (error) {
    throw error;
  }
};

// REGISTER
export const registerUser = async (userData) => {
  try {
    const response = await api.post("/auth/register", userData);
    return response.data;
  } catch (error) {
    throw error;
  }
};

// LOGOUT
export const logoutUser = () => {
  localStorage.removeItem("token");
};

/* =====================================================
   ADMIN USER SERVICES
===================================================== */

// GET ALL USERS
export const getAllUsers = async () => {
  try {
    const response = await api.get("/admin/users");
    return response.data;
  } catch (error) {
    throw error;
  }
};

// GET SINGLE USER
export const getUserByphone = async (phone) => {
  try {
    const response = await api.get(`/admin/users/${phone}`);
    return response.data;
  } catch (error) {
    throw error;
  }
};

// UPDATE USER
export const updateUser = async (phone, updatedData) => {
  try {
    const response = await api.put(`/admin/users/${phone}`, updatedData);
    return response.data;
  } catch (error) {
    throw error;
  }
};

// DELETE USER
export const deleteUser = async (phone) => {
  try {
    const response = await api.delete(`/admin/users/${phone}`);
    return response.data;
  } catch (error) {
    throw error;
  }
};
